<script setup lang="ts">
import { computed, ref } from 'vue'
import QRCode from 'qrcode'
import { CheckCircle2, Copy, Fingerprint, KeyRound, ShieldCheck } from 'lucide-vue-next'
import Button from '@/components/ui/Button.vue';import StatusBadge from '@/components/ui/StatusBadge.vue';import { confirmTOTP,enrollTOTP } from '@/lib/api';import { useAuthStore } from '@/stores/auth'
const auth=useAuthStore();const secret=ref('');const qr=ref('');const code=ref('');const error=ref('');const enabled=ref(auth.user?.totp_enabled??false);const enrolling=computed(()=>!!secret.value&&!enabled.value)
const start=async()=>{error.value='';try{const data=await enrollTOTP();secret.value=data.secret;qr.value=await QRCode.toDataURL(data.otpauth_uri,{width:220,margin:1,color:{dark:'#07110d',light:'#f8fafc'}})}catch(e:any){error.value=e?.response?.data?.error?.message||'Não foi possível iniciar o TOTP.'}}
const confirm=async()=>{error.value='';try{await confirmTOTP(code.value);enabled.value=true;secret.value='';qr.value='';await auth.initialize()}catch{error.value='Código inválido. Verifique o relógio do dispositivo.'}}
const copy=()=>navigator.clipboard.writeText(secret.value)
</script>
<template><div class="mx-auto max-w-5xl space-y-5"><header><div class="flex items-center gap-2 font-mono text-[10px] uppercase tracking-widest text-signal"><ShieldCheck class="h-3.5 w-3.5"/>Identity hardening</div><h1 class="mt-3 text-3xl font-semibold tracking-tight">Security settings</h1><p class="mt-2 text-sm text-muted">Proteja ações críticas com identidade forte verificada no servidor.</p></header><section class="grid gap-5 lg:grid-cols-[1fr_340px]"><article class="rounded-xl border border-line bg-panel/65"><header class="flex items-start gap-4 border-b border-line p-5"><div class="grid h-10 w-10 place-items-center rounded-xl border border-signal/20 bg-signal/[.07]"><Fingerprint class="h-5 w-5 text-signal"/></div><div class="flex-1"><div class="flex items-center gap-3"><h2 class="text-sm font-medium">Time-based one-time password</h2><StatusBadge :status="enabled?'healthy':'warning'" :label="enabled?'enabled':'required'"/></div><p class="mt-1 text-xs leading-5 text-muted">RFC 6238 · SHA-1 · 30 segundos · segredo AES-256-GCM at rest</p></div></header><div class="p-5"><div v-if="enabled" class="flex items-center gap-3 rounded-xl border border-signal/15 bg-signal/[.04] p-4"><CheckCircle2 class="h-5 w-5 text-signal"/><div><p class="text-sm text-slate-200">Segundo fator ativo</p><p class="mt-1 text-xs text-muted">Ações críticas remotas e cloud agora exigem um código válido.</p></div></div><div v-else-if="!enrolling"><p class="max-w-xl text-sm leading-6 text-muted">Use Aegis, 1Password, Bitwarden ou outro autenticador compatível. O segredo aparece apenas durante este fluxo.</p><Button class="mt-5" @click="start"><KeyRound class="h-4 w-4"/>Configurar autenticador</Button></div><div v-else class="grid gap-6 md:grid-cols-[220px_1fr]"><img :src="qr" alt="QR code para configurar TOTP" class="h-[220px] w-[220px] rounded-xl bg-white p-2"/><div><p class="text-sm font-medium">Escaneie e confirme</p><p class="mt-2 text-xs leading-5 text-muted">Se não puder escanear, copie a chave manualmente:</p><button class="mt-3 flex w-full cursor-pointer items-center gap-2 rounded-lg border border-line bg-slate-950/60 p-3 text-left font-mono text-xs text-slate-300 hover:border-slate-600" @click="copy"><span class="min-w-0 flex-1 break-all">{{secret}}</span><Copy class="h-4 w-4 shrink-0 text-muted"/></button><form class="mt-4 flex gap-2" @submit.prevent="confirm"><input v-model="code" required inputmode="numeric" pattern="[0-9]{6}" maxlength="6" class="field mt-0 font-mono tracking-[.3em]" placeholder="000000" aria-label="Código TOTP"/><Button type="submit">Confirmar</Button></form></div></div><p v-if="error" class="mt-4 rounded-lg border border-danger/20 bg-danger/5 px-3 py-2 text-xs text-danger">{{error}}</p></div></article><aside class="rounded-xl border border-line bg-panel/50 p-5"><p class="font-mono text-[9px] uppercase tracking-widest text-muted">Current operator</p><p class="mt-3 text-sm text-slate-200">{{auth.user?.display_name}}</p><p class="mt-1 text-xs text-muted">{{auth.user?.email}}</p><div class="mt-5 border-t border-line pt-4"><p class="font-mono text-[9px] uppercase tracking-widest text-muted">Roles</p><div class="mt-2 flex flex-wrap gap-2"><StatusBadge v-for="role in auth.user?.roles" :key="role" status="info" :label="role"/></div></div></aside></section></div></template>

